import { auth } from "@/auth";
import { redirect } from "next/navigation";
import DashboardLayout from "@/app/components/DashboardLayout";
import { getMyApplications } from "@/app/actions/applications";

const STATUS_CONFIG: Record<string, { label: string; color: string; bg: string }> = {
    PENDING: { label: "Đang chờ", color: "#92400E", bg: "#FEF3C7" },
    REVIEWING: { label: "Đang xem xét", color: "#1E40AF", bg: "#DBEAFE" },
    INTERVIEW: { label: "Phỏng vấn", color: "#6B21A8", bg: "#F3E8FF" },
    ACCEPTED: { label: "Chấp nhận ✓", color: "#14532D", bg: "#DCFCE7" },
    REJECTED: { label: "Từ chối", color: "#991B1B", bg: "#FEE2E2" },
};

export default async function ApplicationsPage() {
    const session = await auth();
    if (!session?.user || session.user.role !== "CANDIDATE") redirect("/login");

    const applications = await getMyApplications();

    return (
        <DashboardLayout role="CANDIDATE" userName={session.user.name || "Ứng viên"}>
            <div style={{ padding: "2rem" }}>
                <h1 style={{ fontSize: "1.5rem", fontWeight: 800, color: "var(--text)", marginBottom: "0.375rem" }}>
                    Đơn ứng tuyển
                </h1>
                <p style={{ color: "var(--text-muted)", marginBottom: "2rem" }}>
                    Theo dõi trạng thái {applications.length} đơn ứng tuyển của bạn.
                </p>

                {applications.length === 0 ? (
                    <div className="card" style={{ padding: "4rem", textAlign: "center", color: "var(--text-muted)" }}>
                        <svg width="48" height="48" fill="none" stroke="var(--border)" strokeWidth="1.5" viewBox="0 0 24 24" style={{ margin: "0 auto 1rem" }}>
                            <path strokeLinecap="round" strokeLinejoin="round" d="M9 5H7a2 2 0 0 0-2 2v12a2 2 0 0 0 2 2h10a2 2 0 0 0 2-2V7a2 2 0 0 0-2-2h-2M9 5a2 2 0 0 0 2 2h2a2 2 0 0 0 2-2M9 5a2 2 0 0 1 2-2h2a2 2 0 0 1 2 2" />
                        </svg>
                        <p style={{ fontWeight: 600 }}>Chưa có đơn ứng tuyển nào</p>
                        <a href="/jobs" className="btn-primary" style={{ display: "inline-flex", marginTop: "1rem" }}>Tìm việc ngay</a>
                    </div>
                ) : (
                    <div style={{ display: "flex", flexDirection: "column", gap: "1rem" }}>
                        {applications.map((app) => {
                            const st = STATUS_CONFIG[app.status] || { label: app.status, color: "#64748B", bg: "#F8FAFC" };
                            return (
                                <div key={app.id} className="card" style={{ padding: "1.5rem", display: "flex", gap: "1.25rem", alignItems: "center", flexWrap: "wrap" }}>
                                    <div style={{ width: "48px", height: "48px", borderRadius: "10px", background: "var(--tag-bg)", display: "flex", alignItems: "center", justifyContent: "center", fontWeight: 800, color: "var(--primary)", flexShrink: 0 }}>
                                        {app.job.company.name.charAt(0)}
                                    </div>
                                    <div style={{ flex: 1, minWidth: "200px" }}>
                                        <div style={{ fontWeight: 700, color: "var(--text)", fontSize: "1rem" }}>{app.job.title}</div>
                                        <div style={{ fontSize: "0.875rem", color: "var(--text-muted)", marginTop: "0.125rem" }}>
                                            {app.job.company.name} · {app.job.location}
                                        </div>
                                    </div>
                                    <div style={{ display: "flex", gap: "1rem", alignItems: "center", flexWrap: "wrap" }}>
                                        <span style={{ fontSize: "0.75rem", fontWeight: 700, padding: "0.375rem 0.875rem", borderRadius: "100px", background: st.bg, color: st.color }}>
                                            {st.label}
                                        </span>
                                        <span style={{ fontSize: "0.8125rem", color: "var(--text-muted)" }}>
                                            {new Date(app.createdAt).toLocaleDateString("vi-VN")}
                                        </span>
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                )}
            </div>
        </DashboardLayout>
    );
}
